const body = $('Webhook - Nhận tin nhắn KH').item.json['body'];

const customerId      = body['customer_id'] || '';
const sessionId       = body['session_id']  || ('session_' + Date.now());
const customerMessage = body['message']     || '';
const allProducts     = body['products']    || [];
const cartItems       = body['cart']        || [];
const purchaseHistory = body['purchase_history'] || [];

// Filter products: in-stock first, then relevance by keyword match, max 15
const msgWords = customerMessage.toLowerCase().split(/\s+/);
const inStock = allProducts.filter(function(p) { return p['stock'] > 0; });
function score(p) {
  const text = (p['name'] + ' ' + p['category'] + ' ' + (p['description'] || '')).toLowerCase();
  return msgWords.reduce(function(n, w) { return n + (text.includes(w) ? 1 : 0); }, 0);
}
const relevantProducts = inStock
  .map(function(p) { return { p: p, s: score(p) }; })
  .sort(function(a, b) { return b.s - a.s; })
  .slice(0, 15)
  .map(function(x) { return x.p; });

// Format catalog (compact)
const productCatalog = relevantProducts.map(function(p) {
  const priceNum     = Number(p['price'])      || 0;
  const salePriceNum = Number(p['sale_price']) || 0;
  const priceStr = (salePriceNum > 0 && salePriceNum < priceNum)
    ? salePriceNum.toLocaleString('vi-VN') + 'đ (giảm từ ' + priceNum.toLocaleString('vi-VN') + 'đ)'
    : priceNum.toLocaleString('vi-VN') + 'đ';
  const desc = (p['description'] || '').slice(0, 80);
  return '[' + p['sku'] + '] ' + p['name'] + ' | ' + p['category'] + ' | ' + priceStr + ' | ' + desc;
}).join('\n');

// Format cart (compact)
const cartSummary = cartItems.length > 0
  ? cartItems.map(function(c) {
      return '[' + c['sku'] + '] ' + c['name'] + ' ×' + c['quantity'];
    }).join(', ')
  : 'Trống';

// Format history (compact, max 5)
const historySummary = purchaseHistory.length > 0
  ? purchaseHistory.slice(0, 5).map(function(h) {
      return '[' + h['sku'] + '] ' + h['name'] + ' x' + (h['times_bought'] || 1);
    }).join(', ')
  : 'Chưa có';

const systemPrompt = `Tư vấn viên Dole Saigon. Quy tắc: chỉ dùng sản phẩm trong catalog, tối đa 3-5 gợi ý, tiếng Việt ngắn gọn, kèm [SKU]. Trả JSON: {"reply":"...","recommendations":[{"sku":"...","name":"...","reason":"...","price":0,"category":"..."}],"intent":"product_query|price_check|recommendation|complaint|other"}`;

const userPrompt = `KH: ${customerMessage}\nGiỏ: ${cartSummary}\nLịch sử: ${historySummary}\n\nCATALOG (${relevantProducts.length} sản phẩm liên quan):\n${productCatalog}\n\nTrả JSON.`;

return [{
  json: {
    customer_id:      customerId,
    session_id:       sessionId,
    customer_message: customerMessage,
    system_prompt:    systemPrompt,
    user_prompt:      userPrompt,
    product_count:    relevantProducts.length
  }
}];

