let rawText = $json['text'] || $json['output'] || $json['response']?.text || '';

// Parse JSON from AI reply
let parsed = null;
try {
  parsed = JSON.parse(rawText);
} catch(e1) {
  try {
    const match = rawText.match(/\{[\s\S]*\}/);
    if (match) parsed = JSON.parse(match[0]);
    else throw new Error('No JSON');
  } catch(e2) {
    parsed = {
      reply: rawText || 'Xin lỗi, tôi không thể xử lý yêu cầu. Vui lòng thử lại.',
      recommendations: [],
      intent: 'other'
    };
  }
}

const recs = (parsed['recommendations'] || []).slice(0, 5).map(function(r) {
  return {
    sku:      r['sku']      || '',
    name:     r['name']     || '',
    reason:   r['reason']   || '',
    price:    r['price']    || 0,
    category: r['category'] || ''
  };
});

return [{
  json: {
    customer_id:      prev['customer_id'],
    session_id:       prev['session_id'],
    original_message: prev['customer_message'],
    reply:            parsed['reply'] || '',
    recommendations:  recs,
    intent:           parsed['intent'] || 'other',
    meta: {
      model:     'amazon.nova-micro-v1:0',
      timestamp: new Date().toISOString()
    }
  }
}];
